package com.clashcoach.api;
import com.clashcoach.player.*; import com.clashcoach.security.AuthService; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.MethodArgumentNotValidException; import org.springframework.web.bind.annotation.*;
/** Converts expected domain errors into the documented REST error envelope. */
@RestControllerAdvice public class ApiExceptionHandler {
 public static class ApiError { private final String code,message;private final Map<String,String> fieldErrors;public ApiError(String code,String message,Map<String,String> fieldErrors){this.code=code;this.message=message;this.fieldErrors=fieldErrors;}public String getCode(){return code;}public String getMessage(){return message;}public Map<String,String> getFieldErrors(){return fieldErrors;} }
 @ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<ApiError> validation(MethodArgumentNotValidException e){Map<String,String> fields=new HashMap<String,String>();e.getBindingResult().getFieldErrors().forEach(error->fields.put(error.getField(),error.getDefaultMessage()));return error(HttpStatus.BAD_REQUEST,"VALIDATION_FAILED","Request validation failed",fields);}@ExceptionHandler({AuthService.InvalidCredentialsException.class,com.clashcoach.security.TokenService.InvalidTokenException.class}) ResponseEntity<ApiError> unauthorized(RuntimeException e){return error(HttpStatus.UNAUTHORIZED,"UNAUTHORIZED","Authentication failed",Collections.<String,String>emptyMap());}@ExceptionHandler(AuthService.DuplicateEmailException.class) ResponseEntity<ApiError> duplicate(RuntimeException e){return error(HttpStatus.CONFLICT,"EMAIL_IN_USE","An account already uses this email",Collections.<String,String>emptyMap());}@ExceptionHandler({PlayerService.PlayerNotLinkedException.class,ClashApiClient.PlayerNotFoundException.class}) ResponseEntity<ApiError> notFound(RuntimeException e){return error(HttpStatus.NOT_FOUND,"PLAYER_NOT_FOUND",e instanceof ClashApiClient.PlayerNotFoundException?"Player was not found by Clash API":"No player is linked",Collections.<String,String>emptyMap());}@ExceptionHandler(PlayerService.PlayerAlreadyLinkedException.class) ResponseEntity<ApiError> conflict(RuntimeException e){return error(HttpStatus.CONFLICT,"PLAYER_ALREADY_LINKED","This player tag cannot be linked",Collections.<String,String>emptyMap());}@ExceptionHandler(ClashApiClient.ProviderUnavailableException.class) ResponseEntity<ApiError> provider(ClashApiClient.ProviderUnavailableException e){return error(HttpStatus.BAD_GATEWAY,"CLASH_API_UNAVAILABLE",e.getMessage(),Collections.<String,String>emptyMap());} private ResponseEntity<ApiError> error(HttpStatus status,String code,String message,Map<String,String> fields){return ResponseEntity.status(status).body(new ApiError(code,message,fields));}
}
